mapper.select:
SELECT U.USER_ID AS USER_ID, U.USER_NO AS USER_NO, U.NAME AS NAME, U.EMAIL AS EMAIL, U.BIRTH_DATE AS BIRTH_DATE, U.ADDRESS_MAIN AS ADDRESS_MAIN, U.ADDRESS_SUB AS ADDRESS_SUB, U.ACTIVE_YN AS ACTIVE_YN, U.CREATED_AT AS CREATED_AT, U.GENDER_FLAG AS GENDER_FLAG, ( SELECT DTL.COMMON_CODE_DTL_NAME FROM JPAS_DB.JPAS_TB_CMMN_CD_DTL DTL WHERE U.GENDER_FLAG = DTL.COMMON_CODE_DTL ) AS GENDER_FLAG_NAME, U.PHONE_NUMBER AS PHONE_NUMBER FROM JPAS_TB_USER U WHERE 1=1
AND U.USER_NO LIKE CONCAT('%', #{userNo}, '%')
AND U.NAME LIKE CONCAT('%', #{name}, '%')
AND U.ACTIVE_YN = #{activeYn}
AND U.GENDER_FLAG = #{genderFlag}
AND U.BIRTH_DATE = #{birthDate}
ORDER BY U.USER_NO
